                </div>
              </SidebarMenuSubItem>
              <SidebarMenuSubItem>
                <SidebarMenuSubButton asChild onClick={() => showSettingsDialog()}>
                  <button type="button" className="flex items-center gap-2">
                    <Settings className="h-4 w-4 shrink-0" />
