                  </button>
                </SidebarMenuSubButton>
              </SidebarMenuSubItem>
            </SidebarMenuSub>
          </CollapsibleContent>
        </SidebarMenuItem>
      </Collapsible>
    );
  }

  return (
    <HoverCardSidebarMenuItem
      icon={<Settings className="h-5 w-5" />}
      description="Settings"
      content={(_isOpen, onClose) => (
        <div className="space-y-2">
